import{_ as e,o as t,c as d,a2 as s}from"./chunks/framework.BWuWLRhz.js";const c="/assets/18-precedence@2x.BYFBuKUb.png",k=JSON.parse('{"title":"18 · config.toml 配置详解：一个文件管住所有旋钮","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"codex/18-config.md","filePath":"codex/18-config.md"}'),a={name:"codex/18-config.md"};function i(n,o,r,l,p,h){return t(),d("div",null,[...o[0]||(o[0]=[s(`<h1 id="_18-·-config-toml-配置详解-一个文件管住所有旋钮" tabindex="-1">18 · config.toml 配置详解：一个文件管住所有旋钮 <a class="header-anchor" href="#_18-·-config-toml-配置详解-一个文件管住所有旋钮" aria-label="Permalink to &quot;18 · config.toml 配置详解：一个文件管住所有旋钮&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇 <a href="./17-computer-use">17 · 电脑操控与浏览器（Computer Use）</a> 让 Codex 长出了手——能看屏幕、点桌面、开浏览器。这一篇从图形界面收回到一个朴素的文本文件——<code>config.toml</code> 。前面十几篇里你零零散散见过它好几回（写沙箱、开 Memory、配模型），这篇把它系统讲清：<strong>这文件放哪、长什么样、哪个键管什么、几个文件叠起来时谁说了算</strong>。</p></blockquote><p>都说配置文件是「装好之后再说」的东西、能跑就别碰——<strong>说句实话，这话用在 Codex 上正好说反了</strong>。</p><p>我自己的经历是这样：2026 年 3 月刚上手那阵，我压根没动过 <code>config.toml</code> ，每次开 Codex 都手动 <code>/model</code> 切模型、<code>/permissions</code> 调权限、临时敲 <code>--search</code> 开联网，一天下来同样的几个动作要重复七八遍。直到有天我数了数——光「切到强模型 + 放开工作区写权限」这套组合，那个礼拜我手动敲了不下三十次。<strong>那一刻才反应过来：我把一个「写一次、永久生效」的事，活生生干成了「每次重来」。</strong></p><p><code>config.toml</code> 的价值恰恰在这——它不是给高手炫技的，是给<strong>所有嫌麻烦的人</strong>省事的。你越懒得每次配，越该花十分钟把它写明白。</p><p>更关键的是，它还藏着一个新手最容易栽的坑：<strong>同一段配置，写在你主目录和写在项目里，效果可能完全不同，甚至项目里那份压根不生效</strong>。这篇就把这套「文件放哪、谁压谁」的规则掰开揉碎，让你写配置时心里有数。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>一句话讲明白 <code>config.toml</code> 是什么、它跟 <code>AGENTS.md</code> 到底分什么工（别再混）</li><li>用户级 <code>~/.codex/config.toml</code> 和项目级 <code>.codex/config.toml</code> 各自放哪、管谁、该写什么</li><li>一张「谁压谁」的优先级表，外加一条新手必栽的安全限制（项目配置有些键写了也白写）</li><li>你最常会动的七八个配置项（<code>model</code>、<code>approval_policy</code>、<code>sandbox_mode</code>、<code>web_search</code>、<code>[features]</code>…）分别干嘛、默认是什么</li><li>一份能照抄的最小配置 + <code>-c</code> 临时改一次的命令 + <code>--profile</code> 切多套配置的实战，跑完自己就能验证</li></ul><hr><h2 id="_01-先搞懂-config-toml-是什么-跟-agents-md-分什么工" tabindex="-1">01 先搞懂：config.toml 是什么，跟 AGENTS.md 分什么工 <a class="header-anchor" href="#_01-先搞懂-config-toml-是什么-跟-agents-md-分什么工" aria-label="Permalink to &quot;01 先搞懂：config.toml 是什么，跟 AGENTS.md 分什么工&quot;">​</a></h2><p>先给结论：<strong><code>config.toml</code> 是 Codex 的「行为旋钮总成」——用 TOML 格式管模型、审批、沙箱、MCP、功能开关这些工具行为；它跟 <code>AGENTS.md</code> 是两套东西，一个管「怎么干活」，一个管「记住什么」。</strong></p><p>很多人一上来就把这俩搞混。你在 <a href="./11-agents-md">11 · AGENTS.md</a> 那篇写了一路项目说明，又在 <a href="./15-permissions">15 · 权限沙箱审批</a> 里调了沙箱——<strong>前者落在 <code>AGENTS.md</code> 里，后者落在 <code>config.toml</code> 里</strong>，装的是完全不同的内容。</p><p><strong>类比：汽车的「驾驶手册」和「中控台旋钮」。</strong> <code>AGENTS.md</code> 像手套箱里那本<strong>驾驶手册</strong>——写的是「这辆车用 95 号油」「冬天先热车再走」这类<strong>给人（给 Codex）看的、自然语言的叮嘱</strong>，它每次开工被读进去当背景知识。<code>config.toml</code> 不一样，它是中控台上那一排<strong>实体旋钮</strong>——空调几度、座椅加热开不开、默认运动模式还是经济模式，<strong>一个个明确的、机器照着执行的开关</strong>。手册是「讲给它听的话」，旋钮是「替它拧死的行为」。</p><p>TOML（Tom&#39;s Obvious Minimal Language，一种给人读写的配置文件格式）是这文件的格式，长这样：顶层是 <code>key = value</code> ，分组用 <code>[表名]</code> 。先扫一眼就懂：</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ~/.codex/config.toml</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gpt-5.5&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">approval_policy = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;on-request&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sandbox_mode = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;workspace-write&quot;</span></span></code></pre></div><p>官方把它的定位说得很干脆：</p><blockquote><p>Codex stores user-level configuration at <code>~/.codex/config.toml</code>.（Codex 把用户级配置存在 <code>~/.codex/config.toml</code> 。）</p></blockquote><p>落到你会遇到的真实场景，<code>config.toml</code> 管的就是这几类事：</p><ul><li><strong>「我每次都想用某个模型，别老让我手动切」</strong>——写 <code>model</code></li><li><strong>「这台机器上，默认就给我工作区写权限 + 出圈才问」</strong>——写 <code>sandbox_mode</code> + <code>approval_policy</code></li><li><strong>「联网搜索我要实时的，别用缓存」</strong>——写 <code>web_search</code></li><li><strong>「把那个实验功能给我开开 / 关关」</strong>——写 <code>[features]</code></li></ul><p>这些都不是「讲给 Codex 听」的话，而是<strong>实打实改变它运行行为的旋钮</strong>。这就是 <code>config.toml</code> 跟 <code>AGENTS.md</code> 的根本分工。</p><blockquote><p>💡 一句话总结：<code>AGENTS.md</code> 是「讲给 Codex 听的自然语言叮嘱」，<code>config.toml</code> 是「替它拧死机器行为的旋钮总成」——<strong>前者管记住什么，后者管怎么干活</strong>，别混着用。</p></blockquote><hr><h2 id="_02-文件放哪-用户级一份、项目级一份" tabindex="-1">02 文件放哪：用户级一份、项目级一份 <a class="header-anchor" href="#_02-文件放哪-用户级一份、项目级一份" aria-label="Permalink to &quot;02 文件放哪：用户级一份、项目级一份&quot;">​</a></h2><p><code>config.toml</code> 最该先搞懂的，不是有哪些键，而是<strong>它至少有两个落脚点：一份在你主目录（管全局），一份可以塞进项目里（只管这个项目）</strong>。开头说的那个坑，根子就在没分清这两处。</p><p><strong>类比：家里的总开关箱 vs 房间里的墙壁开关。</strong> 你家有个<strong>总配电箱</strong>（一般在玄关），管的是全屋默认——比如「夜间总闸限流」。每个房间墙上还有<strong>自己的开关</strong>，只管这间屋，而且优先级更高——书房想开大灯，按书房墙上那个就行，不影响别的屋。<code>config.toml</code> 就是这两层：主目录那份是总配电箱（跨所有项目），项目里那份是房间开关（只管这个项目、还压总闸）。</p><p>官方定义的位置，看这张表：</p><table tabindex="0"><thead><tr><th>层级</th><th>文件位置</th><th>影响谁</th><th>该放什么</th><th>一个前提</th></tr></thead><tbody><tr><td><strong>用户级（User）</strong></td><td><code>~/.codex/config.toml</code></td><td>你，跨你<strong>所有</strong>项目</td><td>个人默认：惯用模型、默认权限档、MCP、通知</td><td>无</td></tr><tr><td><strong>项目级（Project）</strong></td><td><code>&lt;repo&gt;/.codex/config.toml</code></td><td>在这个仓库里干活时</td><td>项目专属：这个项目该用的模型、该有的沙箱档</td><td><strong>项目被信任</strong>才加载</td></tr></tbody></table><p>这里有三个<strong>新手必须记牢</strong>的点：</p><p><strong>第一，主目录那份的路径是固定的：<code>~/.codex/config.toml</code> 。</strong> 这个 <code>~/.codex</code> 目录叫 <code>CODEX_HOME</code> ，是 Codex 存所有本地东西（配置、登录凭据、历史记录、日志）的地方，默认就在你主目录下。文件不存在就自己建一个，Codex 读得到。</p><p><strong>第二，项目级那份要放进仓库里的 <code>.codex/</code> 子目录</strong>（注意是 <code>.codex/config.toml</code> ，带个点的隐藏目录，跟主目录那个 <code>~/.codex</code> 同名但不是一处）。它只在你<strong>在这个项目里干活</strong>时才叠加上来。</p><p><strong>第三，也是最容易忽略的——项目级配置只有「项目被信任」时才加载。</strong> 这是 Codex 的安全设计：怕你随便 clone 一个陌生仓库，它里头藏的 <code>.codex/config.toml</code> 偷偷给自己放权。官方写得很直白：</p><blockquote><p>If you mark a project as untrusted, Codex skips project-scoped <code>.codex/</code> layers, including project-local config, hooks, and rules.（如果你把项目标记为不信任，Codex 会跳过项目级 <code>.codex/</code> 层，包括项目本地配置、hooks 和 rules。）</p></blockquote><p>换句话说：<strong>你在一个没信任的项目里写了 <code>.codex/config.toml</code> ，它一行都不会生效</strong>——但你主目录那份照常加载。第一次配项目级配置发现「怎么没反应」，先想想这个项目你信任了没（信任是 Codex 第一次进新项目时问你的那一下）。</p><h3 id="实战里怎么分-一条配置该放哪" tabindex="-1">实战里怎么分：一条配置该放哪 <a class="header-anchor" href="#实战里怎么分-一条配置该放哪" aria-label="Permalink to &quot;实战里怎么分：一条配置该放哪&quot;">​</a></h3><p>判断一条配置该放主目录还是放项目里，脑子里过一个问题就够：<strong>「这条只跟我这个人有关，还是跟这个项目有关？」</strong></p><ul><li><strong>「我所有项目都想要」→ 用户级</strong>（<code>~/.codex/config.toml</code>）。比如「我习惯默认用 <code>gpt-5.5</code>」「我的 MCP 服务器」「桌面通知脚本」，配一次，开任何项目都在。</li><li><strong>「就这个项目该这么干」→ 项目级</strong>（<code>&lt;repo&gt;/.codex/config.toml</code>）。比如「这个老项目得用某个特定模型」「这个项目默认收紧到只读」。它跟着仓库走，进 Git 后队友拉下来也有同一套（前提是队友也信任了这个项目）。</li></ul><p>我自己的分法很简单：<strong>主目录那份写「我这个人的习惯」，项目里基本不写、留空</strong>——只有极少数项目有特殊脾气（比如一个我只敢让它只读看、绝不能动手的客户代码库），我才在它的 <code>.codex/config.toml</code> 里单独写一行 <code>sandbox_mode = &quot;read-only&quot;</code> 兜底。这样既不用每次手动收紧，也不会把这条限制误带到别的项目上。</p><blockquote><p>💡 一句话总结：用户级 <code>~/.codex/config.toml</code>（在 <code>CODEX_HOME</code> ，管你所有项目）、项目级 <code>&lt;repo&gt;/.codex/config.toml</code>（只管这个项目、<strong>且项目得被信任才加载</strong>）；判断口诀「跟我这个人走 vs 跟这个项目走」。</p></blockquote><hr><h2 id="_03-谁压谁-优先级-外加一条新手必栽的安全限制" tabindex="-1">03 谁压谁：优先级，外加一条新手必栽的安全限制 <a class="header-anchor" href="#_03-谁压谁-优先级-外加一条新手必栽的安全限制" aria-label="Permalink to &quot;03 谁压谁：优先级，外加一条新手必栽的安全限制&quot;">​</a></h2><p>两处都能写同一个键。那问题来了：<strong>用户级说用 <code>gpt-5.5</code>、项目级说用别的，到底听谁的？</strong> 这就是「优先级（precedence）」要管的事，也是 <code>config.toml</code> 最容易绕晕人的地方。</p><p>而且实际不止两层——加上命令行临时参数、<code>--profile</code> 选的预设档（profile，命名配置文件）、系统级配置，一共能叠到六层。先给官方的完整排序，从<strong>高到低</strong>（高的压低的）：</p><table tabindex="0"><thead><tr><th>优先级</th><th>来源</th><th>说人话</th></tr></thead><tbody><tr><td>1（最高）</td><td><strong>命令行参数 / <code>--config</code></strong></td><td>你这次启动临时拍的板，只管这一次</td></tr><tr><td>2</td><td><strong>项目级</strong> <code>&lt;repo&gt;/.codex/config.toml</code></td><td>这个项目的设置（信任时才算，从根目录到当前目录、<strong>越近的越赢</strong>）</td></tr><tr><td>3</td><td><strong><code>--profile</code> 选的预设档</strong> <code>~/.codex/&lt;名字&gt;.config.toml</code></td><td>你切到的那套命名配置</td></tr><tr><td>4</td><td><strong>用户级</strong> <code>~/.codex/config.toml</code></td><td>你的全局默认</td></tr><tr><td>5</td><td><strong>系统级</strong> <code>/etc/codex/config.toml</code>（Unix，若有）</td><td>管理员给整机定的</td></tr><tr><td>6（最低）</td><td><strong>内置默认值</strong></td><td>你啥都没写时 Codex 自带的</td></tr></tbody></table><p>这个「从高到低」的压制关系，画成一张图你会更有体感——<strong>上面的层盖住下面的层里写了同一个键的部分</strong>：</p><p><img src="`+c+`" alt="config 六层优先级（高压低）"></p><p>这张图把六层配置按优先级从高到低竖着摞起来：最上面「命令行参数 / <code>--config</code>」最具体、压力最大，往下依次是项目级、<code>--profile</code> 预设档、用户级、系统级，最底下是兜底的内置默认值——<strong>上层会盖掉下层写了同一个键的部分</strong>，所以越靠上、越「具体到当下」的设置就越说了算。</p><p>一句话记牢这个顺序：<strong>越「具体到当下」的越大，越「全局兜底」的越小</strong>。命令行（就这一次）压项目（就这项目），项目压预设档，预设档压用户全局，用户压系统，系统压内置兜底。官方点了句最实用的用法：</p><blockquote><p>Use that precedence to set shared defaults in <code>config.toml</code> and keep profile files focused on the values that differ.（用这套优先级把共享默认放在 <code>config.toml</code> ，让 profile 文件只装那些不一样的值。）</p></blockquote><p>也就是说——<strong>主目录写「大多数时候的我」，profile 写「偶尔切过去的那套差异」，命令行管「就这一次的特例」</strong>。这正好印证了上一篇结尾埋的那个悬念：想让某个偏好「一开机就生效」，写进 <code>config.toml</code>（多半是用户级那份）就对了。</p><h3 id="那条新手必栽的限制-项目配置有些键-写了也白写" tabindex="-1">那条新手必栽的限制：项目配置有些键，写了也白写 <a class="header-anchor" href="#那条新手必栽的限制-项目配置有些键-写了也白写" aria-label="Permalink to &quot;那条新手必栽的限制：项目配置有些键，写了也白写&quot;">​</a></h3><p>上面说项目级压用户级。但<strong>有一类键是例外——你在项目级 <code>.codex/config.toml</code> 里写它们，Codex 直接无视，还会在启动时给你打一行警告</strong>。这是 Codex 故意拦的安全红线，新手十有八九会撞。</p><p>为啥拦？想想看：要是一个陌生仓库的 <code>.codex/config.toml</code> 能偷偷改你连的模型服务地址、改你的认证方式、塞个通知命令在你机器上跑——那就太危险了。所以官方把这类「会动到机器级安全」的键，<strong>锁死在只能写用户级</strong>。官方原文点了名：</p><blockquote><p>Codex ignores <code>openai_base_url</code>, <code>chatgpt_base_url</code>, <code>apps_mcp_product_sku</code>, <code>model_provider</code>, <code>model_providers</code>, <code>notify</code>, <code>profile</code>, <code>profiles</code>, <code>experimental_realtime_ws_base_url</code>, and <code>otel</code> when they appear in a project-local <code>.codex/config.toml</code>.（当 <code>openai_base_url</code>、<code>chatgpt_base_url</code>、<code>apps_mcp_product_sku</code>、<code>model_provider</code>、<code>model_providers</code>、<code>notify</code>、<code>profile</code>、<code>profiles</code>、<code>experimental_realtime_ws_base_url</code> 和 <code>otel</code> 出现在项目本地的 <code>.codex/config.toml</code> 里时，Codex 会忽略它们。）</p></blockquote><p>翻成大白话，这些键写进项目级会被忽略，得放用户级：</p><table tabindex="0"><thead><tr><th>这类键</th><th>管什么</th><th>为啥只能写用户级</th></tr></thead><tbody><tr><td><code>model_provider</code> / <code>model_providers</code></td><td>模型服务商、接入地址</td><td>防陌生仓库把你的请求引到别处</td></tr><tr><td><code>openai_base_url</code> / <code>chatgpt_base_url</code></td><td>内置服务的基础 URL</td><td>同上，改 URL 等于改数据去向</td></tr><tr><td><code>notify</code></td><td>任务完成时跑的外部命令</td><td>防仓库在你机器上偷偷执行命令</td></tr><tr><td><code>otel</code></td><td>遥测 / 日志导出</td><td>防把你的运行数据外发</td></tr><tr><td><code>profile</code> / <code>profiles</code></td><td>选哪套配置预设</td><td>配置档要靠 <code>--profile</code> 命令行选，不让仓库替你选</td></tr></tbody></table><p><strong>所以记住这条对照：模型服务、通知、遥测、选 profile 这些「机器级」的键，统统写主目录那份；项目级只配 <code>model</code>、<code>sandbox_mode</code>、<code>approval_policy</code> 这类「这个项目本地怎么干活」的键。</strong> 你要是把 <code>model_providers</code> 写进项目级发现没生效，别怀疑语法——它就是被官方拦了。</p><blockquote><p>💡 一句话总结：优先级口诀「<strong>越具体到当下的越大</strong>」（命令行 &gt; 项目 &gt; profile &gt; 用户 &gt; 系统 &gt; 内置）；但<strong>项目级配置碰不了 <code>model_provider</code>、<code>notify</code>、<code>otel</code>、<code>profile</code> 这类机器级键</strong>——写了被忽略还报警告，它们只认用户级。</p></blockquote><hr><h2 id="_04-最常动的几个配置项-干嘛用、默认是什么" tabindex="-1">04 最常动的几个配置项：干嘛用、默认是什么 <a class="header-anchor" href="#_04-最常动的几个配置项-干嘛用、默认是什么" aria-label="Permalink to &quot;04 最常动的几个配置项：干嘛用、默认是什么&quot;">​</a></h2><p>层级和优先级理清了，来看你<strong>实际最常会去动</strong>的那几个键。<code>config.toml</code> 官方支持的键有上百个（完整清单在官方 Config Reference），但 90% 的人日常碰的就这么几个。我挑出来，每个讲清「干嘛的、默认是什么」——<strong>默认值尤其重要，知道默认是什么，你才知道哪些根本不用写</strong>。</p><table tabindex="0"><thead><tr><th>配置键</th><th>干嘛的</th><th>默认值（以官方为准）</th><th>常见写法</th></tr></thead><tbody><tr><td><code>model</code></td><td>默认用哪个模型</td><td>跟随 Codex 内置默认</td><td><code>model = &quot;gpt-5.5&quot;</code></td></tr><tr><td><code>approval_policy</code></td><td>啥时候停下来问你</td><td><code>on-request</code></td><td><code>approval_policy = &quot;on-request&quot;</code></td></tr><tr><td><code>sandbox_mode</code></td><td>能动多大（文件 / 网络）</td><td><code>workspace-write</code>（git 仓库，见下注）</td><td><code>sandbox_mode = &quot;workspace-write&quot;</code></td></tr><tr><td><code>model_reasoning_effort</code></td><td>推理使多大劲</td><td>跟随模型 / 预设</td><td><code>model_reasoning_effort = &quot;high&quot;</code></td></tr><tr><td><code>web_search</code></td><td>联网搜索模式</td><td><code>cached</code>（缓存）</td><td><code>web_search = &quot;live&quot;</code></td></tr><tr><td><code>personality</code></td><td>沟通风格</td><td><code>friendly</code>（示例值）</td><td><code>personality = &quot;pragmatic&quot;</code></td></tr><tr><td><code>file_opener</code></td><td>引用文件点击用哪个编辑器打开</td><td><code>vscode</code></td><td><code>file_opener = &quot;cursor&quot;</code></td></tr></tbody></table><blockquote><p><strong>关于 <code>sandbox_mode</code> 默认值的一点澄清</strong>：直接裸跑 <code>codex</code> 走的是 Auto 预设——<strong>git 仓库里默认 <code>workspace-write</code></strong>（能读写工作区文件），<strong>非 git 目录默认 <code>read-only</code></strong>（只读）。官方把「<code>workspace-write</code>」称为「the default sandbox mode」，指的就是最常见的 git 仓库场景。</p></blockquote><p>逐个说几句你最该知道的细节：</p><h3 id="model-model-reasoning-effort-approval-policy-sandbox-mode" tabindex="-1">model / model_reasoning_effort / approval_policy / sandbox_mode <a class="header-anchor" href="#model-model-reasoning-effort-approval-policy-sandbox-mode" aria-label="Permalink to &quot;model / model_reasoning_effort / approval_policy / sandbox_mode&quot;">​</a></h3><p>这四个是<strong>重头戏，但前面篇章已经讲透了，这里不重复</strong>：模型选择在 <a href="./05-third-party-models">05 · 第三方模型</a>，审批策略（approval policy，<code>approval_policy</code> 键）和沙箱模式（sandbox mode，<code>sandbox_mode</code> 键）在 <a href="./15-permissions">15 · 权限沙箱审批</a> 用「档位和限速」讲过。本篇你只需记住一件事：<strong>它们都在 <code>config.toml</code> 里有对应的键，写进去就是把那套行为定成默认</strong>，不用每次 <code>/model</code> 或 <code>--sandbox</code> 临时调。</p><p><code>model_reasoning_effort</code> 是推理强度，官方给的档位是 <code>minimal | low | medium | high | xhigh</code>（<code>xhigh</code> 看模型支不支持）。简单活儿调低省时间省额度，硬骨头调 <code>high</code>。</p><h3 id="web-search-联网搜索-注意默认是「缓存」不是「实时」" tabindex="-1">web_search：联网搜索，注意默认是「缓存」不是「实时」 <a class="header-anchor" href="#web-search-联网搜索-注意默认是「缓存」不是「实时」" aria-label="Permalink to &quot;web_search：联网搜索，注意默认是「缓存」不是「实时」&quot;">​</a></h3><p>这个键有个<strong>反直觉的默认</strong>，我第一次就栽了。Codex 默认开着联网搜索，但用的是 <code>cached</code>（缓存）模式——查的是 OpenAI 维护的一个网页索引，<strong>返回的是预先收录好的结果，不是当场去抓实时网页</strong>。官方解释这么设计是为了降低提示注入（prompt injection）风险：缓存内容比任意实时页面安全些。</p><p>我去年有次让 Codex 查「某个库的最新版本号」，它给的数对不上——折腾半天才发现是缓存模式给的旧索引。<strong>要查实时的，得显式改</strong>：</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">web_search = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;live&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 实时抓取，等价于命令行 --search</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># web_search = &quot;cached&quot;   # 默认：走缓存索引</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># web_search = &quot;disabled&quot; # 彻底关掉搜索工具</span></span></code></pre></div><p>有个例外要知道：<strong>如果你用了 <code>--yolo</code> 或别的完全访问沙箱，<code>web_search</code> 会自动变成 <code>live</code></strong>。</p><h3 id="personality-让-codex-换个说话风格" tabindex="-1">personality：让 Codex 换个说话风格 <a class="header-anchor" href="#personality-让-codex-换个说话风格" aria-label="Permalink to &quot;personality：让 Codex 换个说话风格&quot;">​</a></h3><p><code>personality</code> 调沟通风格，官方给的值是 <code>none | friendly | pragmatic</code>（友好 / 务实）。会话里也能临时用 <code>/personality</code> 切。我自己常驻 <code>pragmatic</code>——少点寒暄，直接给结论，对老手更顺。</p><h3 id="file-opener-让引用的文件能点开" tabindex="-1">file_opener：让引用的文件能点开 <a class="header-anchor" href="#file-opener-让引用的文件能点开" aria-label="Permalink to &quot;file_opener：让引用的文件能点开&quot;">​</a></h3><p>Codex 输出里经常带 <code>某文件.py:42</code> 这种引用。<code>file_opener</code> 决定点它用哪个编辑器跳转，默认 <code>vscode</code> ，可选 <code>vscode-insiders | windsurf | cursor | none</code> 。用 Cursor 的把它改成 <code>cursor</code> ，引用就变成可点击的链接，直接跳到那一行。</p><h3 id="一个-toml-的小坑-根键必须写在表前面" tabindex="-1">一个 TOML 的小坑：根键必须写在表前面 <a class="header-anchor" href="#一个-toml-的小坑-根键必须写在表前面" aria-label="Permalink to &quot;一个 TOML 的小坑：根键必须写在表前面&quot;">​</a></h3><p>这是写 <code>config.toml</code> 最常见的语法错。TOML 规定：<strong>所有顶层的 <code>key = value</code>（根键）必须写在所有 <code>[表]</code> 的前面</strong>。官方示例配置文件的注释里也特别提醒了这条：</p><blockquote><p>Root keys must appear before tables in TOML.（在 TOML 里，根键必须出现在表之前。）</p></blockquote><p>啥意思？看个对错对比就懂：</p><table tabindex="0"><thead><tr><th>❌ 错的（根键混在表后面）</th><th>✅ 对的（根键全在前、表全在后）</th></tr></thead><tbody><tr><td><code>[features]</code><br><code>hooks = true</code><br><code>model = &quot;gpt-5.5&quot;</code> ← 报错</td><td><code>model = &quot;gpt-5.5&quot;</code><br><code>[features]</code><br><code>hooks = true</code></td></tr></tbody></table><p>记法：<strong>先写所有不带 <code>[]</code> 的单行键（<code>model</code>、<code>approval_policy</code>…），再写所有 <code>[表]</code> 段。</strong> 顺序反了，TOML 解析直接报错，而且报错信息常让新手摸不着头脑。</p><blockquote><p>💡 一句话总结：高频键就这几个——<code>model</code>、<code>approval_policy</code>、<code>sandbox_mode</code>、<code>model_reasoning_effort</code>、<code>web_search</code>（默认 <code>cached</code> 不是实时！）、<code>personality</code>、<code>file_opener</code>；<strong>默认值心里有数，没特殊需求就别写</strong>；还有个 TOML 铁律——根键必须写在所有 <code>[表]</code> 前面。</p></blockquote><hr><h2 id="_05-features-实验和可选功能的总开关" tabindex="-1">05 [features]：实验和可选功能的总开关 <a class="header-anchor" href="#_05-features-实验和可选功能的总开关" aria-label="Permalink to &quot;05 [features]：实验和可选功能的总开关&quot;">​</a></h2><p>有一类配置单拎出来说——<code>[features]</code> 表，它是 Codex <strong>所有可选 / 实验功能的总开关板</strong>。前面好几篇提到的功能（Memory、hooks、子代理协作）开不开，根子都在这。</p><p><strong>类比：手机「实验室 / 开发者选项」里那一排开关。</strong> 系统稳定功能默认就开着，但还有一格「实验室」，里头一排可以手动拨的开关——有的默认开、有的默认关，拨一下某个新功能就生效或失效。<code>[features]</code> 就是 Codex 的这格实验室：<strong>每个功能一个布尔开关，写 <code>true</code> 开、写 <code>false</code> 关、不写就用它自己的默认</strong>。</p><p>写法就是一个 <code>[features]</code> 表，底下列功能名：</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">features</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">memories = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 开启 Memory（记忆）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">shell_snapshot = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 快照 shell 环境、加速重复命令</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">hooks = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # 关掉生命周期 hooks</span></span></code></pre></div><p>官方列了一批功能开关，挑几个你可能会动的，<strong>默认值以官方为准</strong>：</p><table tabindex="0"><thead><tr><th>功能键</th><th>默认</th><th>成熟度</th><th>干嘛的</th></tr></thead><tbody><tr><td><code>hooks</code></td><td><code>true</code></td><td>稳定</td><td>生命周期 hooks（事件触发脚本）</td></tr><tr><td><code>multi_agent</code></td><td><code>true</code></td><td>稳定</td><td>子代理协作工具</td></tr><tr><td><code>shell_snapshot</code></td><td><code>true</code></td><td>稳定</td><td>快照 shell 环境、加速重复命令</td></tr><tr><td><code>fast_mode</code></td><td><code>true</code></td><td>稳定</td><td>快速响应模式（节省等待时间）</td></tr><tr><td><code>shell_tool</code></td><td><code>true</code></td><td>稳定</td><td>内置 shell 工具（执行终端命令）</td></tr><tr><td><code>personality</code></td><td><code>true</code></td><td>稳定</td><td>沟通风格选择控件</td></tr><tr><td><code>memories</code></td><td><code>false</code></td><td>稳定</td><td>Memory（记忆系统，下一篇讲）</td></tr><tr><td><code>codex_git_commit</code></td><td><code>false</code></td><td>实验性</td><td>让 Codex 自动生成 git commit 信息</td></tr><tr><td><code>apps</code></td><td><code>false</code></td><td>实验性</td><td>ChatGPT Apps / 连接器支持</td></tr><tr><td><code>undo</code></td><td><code>false</code></td><td>稳定</td><td>用 git ghost 快照支持撤销</td></tr><tr><td>……</td><td>—</td><td>—</td><td>更多键见官方 Config Reference</td></tr></tbody></table><blockquote><p>⚠️ <strong>实验性功能，可能随版本变化。</strong> 上表带「实验性」的（以及没列出的更多开关）默认值、成熟度都可能随版本调整，开之前<strong>以官方 Config Reference 和你本地实际为准</strong>，别照我这表写死。</p></blockquote><p>注意一个<strong>容易踩的坑</strong>：有些老写法（比如在 <code>[features]</code> 里用 <code>codex_hooks = true</code> 开 hooks）已经过时了——官方现在的规范键名是 <code>hooks</code> ，<code>codex_hooks</code> 只是个被弃用的别名。<strong>以官方现行键名为准</strong>，别跟着旧资料抄。</p><p>开关三种动法，官方都给了：</p><ul><li><strong><code>config.toml</code> 里</strong>：在 <code>[features]</code> 下写 <code>功能名 = true</code>（或 <code>false</code>）。</li><li><strong>命令行临时开</strong>：<code>codex --enable 功能名</code> ，多个就 <code>--enable a --enable b</code> 。</li><li><strong>关掉</strong>：在 <code>[features]</code> 里把那个键设成 <code>false</code> 。</li></ul><p>我的建议：<strong>新手别一上来把实验功能全拨开</strong>。Memory 这种（<a href="./19-memory">19 篇</a> 专讲）想试就 <code>memories = true</code> 开一个，其余保持默认。开太多实验功能，出了怪问题你都不知道该怪谁。</p><blockquote><p>💡 一句话总结：<code>[features]</code> 是「可选 / 实验功能总开关板」，每个功能一个布尔值，写 <code>true</code>/<code>false</code> 改、不写用默认（<code>hooks</code>/<code>multi_agent</code>/<code>shell_snapshot</code> 默认开，<code>memories</code>/<code>apps</code> 默认关）；命令行可用 <code>--enable</code> 临时开；<strong>键名以官方现行为准，旧资料的 <code>codex_hooks</code> 已弃用</strong>。</p></blockquote><hr><h2 id="_06-临时改一次-vs-切一整套-c-和-profile" tabindex="-1">06 临时改一次 vs 切一整套：-c 和 --profile <a class="header-anchor" href="#_06-临时改一次-vs-切一整套-c-和-profile" aria-label="Permalink to &quot;06 临时改一次 vs 切一整套：-c 和 --profile&quot;">​</a></h2><p>有两类需求 <code>config.toml</code> 单靠「写文件」满足不了：<strong>这次就想改一个键、下次还原</strong>，和<strong>我有好几套配置想随时切</strong>。Codex 给了两个工具。</p><h3 id="临时改一次-c-config-不动文件" tabindex="-1">临时改一次：-c / --config（不动文件） <a class="header-anchor" href="#临时改一次-c-config-不动文件" aria-label="Permalink to &quot;临时改一次：-c / --config（不动文件）&quot;">​</a></h3><p>不想为了试一个值专门去改文件，命令行直接覆盖：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 优先用专属 flag（有的话）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gpt-5.4</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 没有专属 flag 的键，用 -c / --config 通用覆盖（值是 TOML 写法，不是 JSON）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> model=&#39;&quot;gpt-5.4&quot;&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> log_dir=./.codex-log</span></span></code></pre></div><p><strong>两个容易踩的点</strong>，官方专门提醒了：</p><ul><li><strong><code>-c</code> 的值按 TOML 解析</strong>，不是 JSON。所以字符串值要带引号（像上面 <code>model=&#39;&quot;gpt-5.4&quot;&#39;</code> 外层单引号给 shell、内层双引号给 TOML），拿不准就把值整个引起来，免得 shell 按空格拆开。</li><li><strong>嵌套键用点号</strong>写，比如 <code>codex -c mcp_servers.context7.enabled=false</code> 。</li></ul><p>这招最适合「试一下某个值好不好使」——满意了再写进文件，不满意拍拍屁股走人，文件没动过。</p><h3 id="切一整套-profile-预设档" tabindex="-1">切一整套：--profile（预设档） <a class="header-anchor" href="#切一整套-profile-预设档" aria-label="Permalink to &quot;切一整套：--profile（预设档）&quot;">​</a></h3><p><a href="./15-permissions">15 篇</a> 提过 profile（配置预设档），这里补全它的机制。<strong>一个 profile 就是 <code>CODEX_HOME</code> 下一个单独的文件</strong>，名字是 <code>&lt;档名&gt;.config.toml</code> ：</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ~/.codex/deep-review.config.toml</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gpt-5.5&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model_reasoning_effort = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;xhigh&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">approval_policy = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;on-request&quot;</span></span></code></pre></div><p>用 <code>--profile</code> 选它：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --profile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deep-review</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --profile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deep-review</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;review this change&quot;</span></span></code></pre></div><p>机制是：Codex 先读你的用户级 <code>~/.codex/config.toml</code> ，再把 <code>~/.codex/deep-review.config.toml</code> 盖上去。所以<strong>profile 文件里只写「跟基础配置不一样的那几个键」就行</strong>，相同的不用重复。</p><p>这里有个<strong>版本变动的坑要标清</strong>：</p><blockquote><p>⚠️ <strong>以官方为准的版本差异。</strong> 官方说明：在 Codex 0.134.0 及以后，<code>--profile</code> <strong>不再</strong>读 <code>config.toml</code> 里的 <code>[profiles.档名]</code> 这种写法，顶层的 <code>profile = &quot;档名&quot;</code> 选择器也不再支持。老配置得把 <code>[profiles.x]</code> 段的内容<strong>搬到单独的 <code>~/.codex/x.config.toml</code> 文件</strong>里。你装的版本不同行为可能不同，<strong>具体以你本地版本和官方文档为准</strong>。</p></blockquote><p>我自己常驻两套 profile：一套 <code>quick</code>（轻模型 + 只读，看代码用），一套 <code>build</code>（强模型 + 工作区写，真干活用）。开 Codex 时一句 <code>codex --profile build</code> 就进对了档，比每次手动调四五个键省事太多——<strong>这正是我开篇说「每周手动配三十次」那个蠢事的解药</strong>。</p><blockquote><p>💡 一句话总结：临时改一个键用 <code>-c key=value</code>（值按 TOML 解析、字符串要引号、嵌套用点号），不动文件；要切一整套配置，把差异写进 <code>~/.codex/&lt;名字&gt;.config.toml</code> 用 <code>--profile &lt;名字&gt;</code> 选——<strong>注意 0.134.0+ 不再支持 <code>[profiles.x]</code> 旧写法，以官方为准</strong>。</p></blockquote><hr><h2 id="_07-动手-写一份配置-→-临时覆盖-→-切-profile-全验一遍" tabindex="-1">07 动手：写一份配置 → 临时覆盖 → 切 profile，全验一遍 <a class="header-anchor" href="#_07-动手-写一份配置-→-临时覆盖-→-切-profile-全验一遍" aria-label="Permalink to &quot;07 动手：写一份配置 → 临时覆盖 → 切 profile，全验一遍&quot;">​</a></h2><p>光看不练假把式。下面带你把这一篇的「写文件 → 临时覆盖 → 切 profile」整条链路跑通。全程最小示例，不依赖你已有的复杂环境。命令、参数严格按官方，<strong>涉及具体模型名我用占位 <code>gpt-5.5</code> ，你照自己能用的型号换</strong>。</p><p><strong>第一步：看一眼你的用户级配置在哪</strong>（在终端）</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.codex/config.toml</span></span></code></pre></div><p><strong>预期</strong>：要么列出这个文件，要么提示不存在。不存在不要紧，下一步建。</p><p><strong>第二步：写一份最小用户级配置</strong></p><p>把下面这份贴进 <code>~/.codex/config.toml</code>（注意根键全在前、<code>[表]</code> 在后）：</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ~/.codex/config.toml</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gpt-5.5&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">approval_policy = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;on-request&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">web_search = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cached&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">features</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">memories = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p><strong>预期</strong>：保存后，这份就是你的全局默认。下一步验证它被读到。</p><p><strong>第三步：进会话，用 /status 确认配置生效</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span></span></code></pre></div><p>进去后敲：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/status</span></span></code></pre></div><p><strong>预期</strong>：在弹出的状态信息里，能看到当前会话用的模型、审批策略等——和你刚写的对得上，说明 <code>config.toml</code> 被成功读到了。（<code>/status</code> 在 <a href="./12-slash-commands">12 篇</a> 见过，是查当前会话状态的命令。）</p><p><strong>第四步：用 -c 临时覆盖一个键，不动文件</strong></p><p>退出会话，这次启动时临时把搜索改成实时：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> web_search=&#39;&quot;live&quot;&#39;</span></span></code></pre></div><p>进去再 <code>/status</code> 看一眼。</p><p><strong>预期</strong>：这一次会话的搜索模式应是 <code>live</code> ，但你<strong>文件里那行 <code>web_search = &quot;cached&quot;</code> 一个字没变</strong>。退出再普通 <code>codex</code> 进去，又变回 <code>cached</code> 。<strong>看到这个「临时改、自动还原」= 第 06 节那条「命令行压配置文件、只管这一次」验证成功</strong>。</p><p><strong>第五步：建一个 profile，体验「切一整套」</strong></p><p>新建文件 <code>~/.codex/quick.config.toml</code>（只写跟基础配置的差异）：</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ~/.codex/quick.config.toml</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gpt-5.5&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sandbox_mode = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;read-only&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">approval_policy = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;untrusted&quot;</span></span></code></pre></div><p>用它启动：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --profile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quick</span></span></code></pre></div><p>进去 <code>/status</code> 确认。</p><p><strong>预期</strong>：这一次的沙箱应是 <code>read-only</code> 、审批是 <code>untrusted</code>（比你主目录那份更严）——因为 profile 盖在用户级之上。<strong>看到这套更严的配置生效 = 第 06 节「profile 是单独文件、用 <code>--profile</code> 切」验证成功</strong>。不带 <code>--profile</code> 普通进去，又回到你用户级那份。</p><p>跑通这五步，你就把 <code>config.toml</code> 最核心的能力亲手验了一遍：<strong>写文件定默认、<code>/status</code> 确认加载、<code>-c</code> 临时覆盖、<code>--profile</code> 切整套</strong>。以后配任何键、任何层，本质都是这套流程。</p><blockquote><p>💡 一句话总结：动手就练「<strong>写用户级配置 → <code>/status</code> 验加载 → <code>-c</code> 临时覆盖且文件不变 → <code>--profile</code> 切一整套更严配置</strong>」——亲手跑通这条链路，「写死默认、临时覆盖、整套切换」三件事立刻就通了。</p></blockquote><hr><h2 id="_08-小结" tabindex="-1">08 小结 <a class="header-anchor" href="#_08-小结" aria-label="Permalink to &quot;08 小结&quot;">​</a></h2><p>这一篇我们把 Codex 那块「旋钮总成」<code>config.toml</code> 从里到外理清了——<strong>从「它是什么」到「放哪、谁压谁、哪些键常动、怎么临时改和切套」，把配置这件事规规矩矩安顿明白</strong>。</p><p>把核心要点串起来回顾：</p><table tabindex="0"><thead><tr><th>你想搞清的事</th><th>答案</th><th>一句话关键点</th></tr></thead><tbody><tr><td>它跟 AGENTS.md 啥关系</td><td>两套东西</td><td>AGENTS.md 管「记住什么」，config.toml 管「怎么干活」</td></tr><tr><td>文件放哪</td><td>两处</td><td>用户级 <code>~/.codex/config.toml</code>、项目级 <code>&lt;repo&gt;/.codex/config.toml</code>（<strong>信任才加载</strong>）</td></tr><tr><td>冲突听谁的</td><td>越具体越大</td><td>命令行 &gt; 项目 &gt; profile &gt; 用户 &gt; 系统 &gt; 内置</td></tr><tr><td>新手必栽的限制</td><td>项目级有禁区</td><td><code>model_provider</code>/<code>notify</code>/<code>otel</code>/<code>profile</code> 等只认用户级</td></tr><tr><td>常动哪几个键</td><td>七八个</td><td><code>model</code>/<code>approval_policy</code>/<code>sandbox_mode</code>/<code>web_search</code>（默认缓存）/<code>[features]</code> 等</td></tr><tr><td>临时改 / 切整套</td><td><code>-c</code> / <code>--profile</code></td><td><code>-c</code> 改一次不动文件，<code>--profile</code> 切一整套预设</td></tr></tbody></table><p><strong>你现在应该能：</strong> 分清 <code>config.toml</code> 和 <code>AGENTS.md</code> 各管什么、知道一条配置该写用户级还是项目级、看懂六层「谁压谁」的优先级以及「项目级碰不了机器级键」这条安全限制、认识 <code>model</code>/<code>approval_policy</code>/<code>sandbox_mode</code>/<code>web_search</code>/<code>[features]</code> 这几组高频配置和它们的默认值，并且会用 <code>-c</code> 临时覆盖、<code>--profile</code> 切整套。<strong>这套「一个文件管住所有旋钮」的能力，是你把 Codex 从「每次手动配」调成「一开机就贴合你习惯」的那把扳手。</strong></p><p>开篇那个「每周手动配三十次」的蠢事，根子就一句话——<strong>我没把该写一次的事写进 <code>config.toml</code></strong>。这一篇之后，你能少走一大圈：<strong>重复在做的配置动作，停下来想想「这是不是该写进配置文件」，再决定放用户级还是项目级。</strong></p><hr><p>下一篇 <strong>19「记忆系统（Memories 与 Chronicle）」</strong>——你刚在 <code>[features]</code> 里见过一个默认关着的 <code>memories</code> 开关，还记得吗？下一篇就专门讲它：<strong>怎么让 Codex 把你的习惯、项目的脉络「记住」</strong>，从每次都像新来的，变成跟你跨会话的老搭档。留个小思考：上一篇它长出了「看屏幕的眼睛」，这一篇它要长出「记得住的脑子」——一个能看、又能记的助手，跟你现在用的，差的是哪一截？</p>`,153)])])}const u=e(a,[["render",i]]);export{k as __pageData,u as default};
